//! Domain-neutral ink topology extraction for handwritten text and arbitrary line art.
//!
//! This module deliberately stops at shape facts: ink mask, connected stroke
//! components, coarse graph counts, and text-likeness priors. Rosetta /
//! aeon-communication owns language-specific interpretation.

use serde::{Deserialize, Serialize};
use std::collections::VecDeque;
#[cfg(not(target_arch = "wasm32"))]
use std::path::Path;

#[cfg(not(target_arch = "wasm32"))]
use crate::mesh_depth_field::{build_mesh_depth_field, MeshDepthConfig};

#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
pub struct TextTopologyConfig {
    /// Luma values at or below this threshold are treated as ink.
    pub ink_threshold: u8,
    /// Drop smaller specks before reporting components.
    pub min_component_area: u32,
    /// Skip topology scoring above this many pixels to avoid large page borders
    /// dominating the symbolic candidate set.
    pub max_component_area_for_text: u32,
}

impl Default for TextTopologyConfig {
    fn default() -> Self {
        Self {
            ink_threshold: 125,
            min_component_area: 3,
            max_component_area_for_text: 6_000,
        }
    }
}

