pub fn analyze_luma_ink(
    image_id: impl Into<String>,
    path: impl Into<String>,
    luma: &[u8],
    width: u32,
    height: u32,
    config: &TextTopologyConfig,
) -> Result<TextTopologyExample, String> {
    if width == 0 || height == 0 {
        return Err("text topology image dimensions must be non-zero".to_string());
    }
    let w = width as usize;
    let h = height as usize;
    let n = w
        .checked_mul(h)
        .ok_or_else(|| "text topology image dimensions overflow".to_string())?;
    if luma.len() != n {
        return Err(format!(
            "luma length {} does not match {}x{}",
            luma.len(),
            width,
            height
        ));
    }

    let mut ink = vec![false; n];
    let mut ink_pixels = 0_u32;
    for (i, &v) in luma.iter().enumerate() {
        if v <= config.ink_threshold {
            ink[i] = true;
            ink_pixels = ink_pixels.saturating_add(1);
        }
    }

    let raw = connected_components(&ink, w, h);
    let mut components = Vec::new();
    for (id, points) in raw.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        components.push(component_topology(id as u32, &points, &ink, w, h, config));
    }

    Ok(TextTopologyExample {
        image_id: image_id.into(),
        path: path.into(),
        width,
        height,
        ink_pixels,
        components,
    })
}

#[cfg(not(target_arch = "wasm32"))]
pub fn analyze_image_file(
    path: &Path,
    config: &TextTopologyConfig,
) -> Result<TextTopologyExample, String> {
    let img = image::open(path).map_err(|e| format!("image decode {}: {}", path.display(), e))?;
    let gray = img.to_luma8();
    let image_id = path
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("image")
        .to_string();
    analyze_luma_ink(
        image_id,
        path.to_string_lossy().to_string(),
        gray.as_raw(),
        gray.width(),
        gray.height(),
        config,
    )
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_cleared_text_like_preview(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
    text_threshold: f32,
    clear_radius: u32,
    max_iterations: u32,
    residual_threshold: f32,
    region_radius: u32,
    pixel_moa_recovery: bool,
) -> Result<u32, String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let mut rgba = img.to_rgba8();
    let width = rgba.width() as usize;
    let height = rgba.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot clear an empty image".to_string());
    }
    let mut total_cleared = 0_u32;
    for _ in 0..max_iterations.max(1).min(12) {
        let cleared = clear_text_like_preview_iteration(
            &mut rgba,
            config,
            text_threshold,
            clear_radius.min(8),
            residual_threshold,
            region_radius.min(24),
            pixel_moa_recovery,
        )?;
        total_cleared = total_cleared.saturating_add(cleared);
        if cleared == 0 {
            break;
        }
    }

    if let Some(parent) = destination.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    rgba.save(destination)
        .map_err(|e| format!("save {}: {}", destination.display(), e))?;
    Ok(total_cleared)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_text_region_mask(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
    text_threshold: f32,
    region_radius: u32,
) -> Result<u32, String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let gray = img.to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot mask an empty image".to_string());
    }
    let mut ink = vec![false; width * height];
    for (i, &v) in gray.as_raw().iter().enumerate() {
        ink[i] = v <= config.ink_threshold;
    }
    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }

    let mut mask = image::GrayImage::new(gray.width(), gray.height());
    let painted = paint_text_stroke_envelope_mask(
        &mut mask,
        &scored_components,
        text_threshold,
        region_radius.min(24),
    );
    if let Some(parent) = destination.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    mask.save(destination)
        .map_err(|e| format!("save {}: {}", destination.display(), e))?;
    Ok(painted)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_text_region_cutout(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
    text_threshold: f32,
    region_radius: u32,
) -> Result<u32, String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let mut rgba = img.to_rgba8();
    let gray = img.to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot cut out an empty image".to_string());
    }
    let mut ink = vec![false; width * height];
    for (i, &v) in gray.as_raw().iter().enumerate() {
        ink[i] = v <= config.ink_threshold;
    }
    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }

    let mut mask = image::GrayImage::new(gray.width(), gray.height());
    let kept = paint_text_stroke_envelope_mask(
        &mut mask,
        &scored_components,
        text_threshold,
        region_radius.min(24),
    );
    for y in 0..rgba.height() {
        for x in 0..rgba.width() {
            if mask.get_pixel(x, y).0[0] == 0 {
                rgba.put_pixel(x, y, image::Rgba([0, 0, 0, 0]));
            }
        }
    }
    if let Some(parent) = destination.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    rgba.save(destination)
        .map_err(|e| format!("save {}: {}", destination.display(), e))?;
    Ok(kept)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_text_region_cutout_preview(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
    text_threshold: f32,
    region_radius: u32,
) -> Result<u32, String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let original = img.to_rgba8();
    let gray = img.to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot preview an empty image".to_string());
    }
    let mut ink = vec![false; width * height];
    for (i, &v) in gray.as_raw().iter().enumerate() {
        ink[i] = v <= config.ink_threshold;
    }
    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }

    let mut mask = image::GrayImage::new(gray.width(), gray.height());
    let kept = paint_text_stroke_envelope_mask(
        &mut mask,
        &scored_components,
        text_threshold,
        region_radius.min(24),
    );
    let mut preview = image::RgbaImage::from_pixel(
        original.width(),
        original.height(),
        image::Rgba([245, 245, 245, 255]),
    );
    for y in 0..original.height() {
        for x in 0..original.width() {
            if mask.get_pixel(x, y).0[0] > 0 {
                preview.put_pixel(x, y, *original.get_pixel(x, y));
            }
        }
    }
    if let Some(parent) = destination.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    preview
        .save(destination)
        .map_err(|e| format!("save {}: {}", destination.display(), e))?;
    Ok(kept)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_depth_probe_images(
    source: &Path,
    depth_destination: &Path,
    confidence_destination: &Path,
    monocular_cue_blend: f32,
) -> Result<(), String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let rgb = img.to_rgb8();
    let width = rgb.width();
    let height = rgb.height();
    let mut rgb_f32 = Vec::with_capacity((width * height * 3) as usize);
    for pixel in rgb.pixels() {
        rgb_f32.push(pixel[0] as f32 / 255.0);
        rgb_f32.push(pixel[1] as f32 / 255.0);
        rgb_f32.push(pixel[2] as f32 / 255.0);
    }
    let mut config = MeshDepthConfig::default();
    config.monocular_cue_blend = monocular_cue_blend.clamp(0.0, 1.0);
    let (field, _) = build_mesh_depth_field(&rgb_f32, width, height, &config, None, None)
        .map_err(|e| format!("mesh depth probe: {}", e))?;
    write_f32_gray_png(depth_destination, width, height, &field.values)?;
    write_f32_gray_png(confidence_destination, width, height, &field.confidence)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_pixel_moa_probe_image(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
) -> Result<(), String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let gray = img.to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot run pixel MOA probe on an empty image".to_string());
    }

    let mut ink = vec![false; width * height];
    for (index, &v) in gray.as_raw().iter().enumerate() {
        ink[index] = v <= config.ink_threshold;
    }
    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }
    let surface_boxes = bubble_like_background_surfaces(&scored_components, width, height);

    let mut values = vec![0.0_f32; width * height];
    for y in 0..height {
        for x in 0..width {
            let index = y * width + x;
            let heads = pixel_moa_head_bank(
                gray.as_raw()[index],
                &ink,
                width,
                height,
                x,
                y,
                &surface_boxes,
            );
            values[index] = fold_pixel_moa_families(&heads);
        }
    }
    write_f32_gray_png(destination, gray.width(), gray.height(), &values)
}

#[cfg(not(target_arch = "wasm32"))]
pub fn write_surface_mask_probe_image(
    source: &Path,
    destination: &Path,
    config: &TextTopologyConfig,
) -> Result<(), String> {
    let img =
        image::open(source).map_err(|e| format!("image decode {}: {}", source.display(), e))?;
    let gray = img.to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    if width == 0 || height == 0 {
        return Err("cannot run surface probe on an empty image".to_string());
    }

    let mut ink = vec![false; width * height];
    for (index, &v) in gray.as_raw().iter().enumerate() {
        ink[index] = v <= config.ink_threshold;
    }
    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }
    let surfaces = bubble_like_background_surfaces(&scored_components, width, height);
    let mut values = vec![0.0_f32; width * height];
    for surface in &surfaces {
        let [x0, y0, x1, y1] = surface.bbox;
        for y in y0..=y1 {
            for x in x0..=x1 {
                if point_in_erodable_surface_interior(surface, x, y, 2) {
                    values[y as usize * width + x as usize] = 0.82;
                } else if point_in_surface_interior(surface, x, y) {
                    values[y as usize * width + x as usize] = 0.38;
                }
            }
        }
    }
    write_f32_gray_png(destination, gray.width(), gray.height(), &values)
}

