#[cfg(not(target_arch = "wasm32"))]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum PixelMoaFamily {
    Ink,
    Rhythm,
    Surface,
    Suppression,
}

#[cfg(not(target_arch = "wasm32"))]
#[derive(Clone, Copy, Debug)]
struct PixelMoaHead {
    id: u8,
    family: PixelMoaFamily,
    value: f32,
}

#[cfg(not(target_arch = "wasm32"))]
fn pixel_moa_head_bank(
    luma: u8,
    ink: &[bool],
    width: usize,
    height: usize,
    x: usize,
    y: usize,
    surfaces: &[SurfaceBox],
) -> [PixelMoaHead; 8] {
    let dark = 1.0 - luma as f32 / 255.0;
    let density_small = local_ink_density(ink, width, height, x, y, 2);
    let density_medium = local_ink_density(ink, width, height, x, y, 5);
    let rhythm_horizontal = local_horizontal_rhythm(ink, width, height, x, y);
    let rhythm_vertical = local_vertical_rhythm(ink, width, height, x, y);
    let surface_owned = if surfaces
        .iter()
        .any(|surface| point_in_surface_interior(surface, x as u32, y as u32))
    {
        0.78
    } else {
        0.12
    };
    let contour_pressure = (density_medium - density_small).abs().clamp(0.0, 1.0);
    let face_mark_pressure = if density_small > 0.18
        && rhythm_horizontal < 0.35
        && !surfaces
            .iter()
            .any(|surface| point_in_surface_interior(surface, x as u32, y as u32))
    {
        0.7
    } else {
        0.1
    };

    [
        PixelMoaHead {
            id: 0,
            family: PixelMoaFamily::Ink,
            value: dark,
        },
        PixelMoaHead {
            id: 1,
            family: PixelMoaFamily::Ink,
            value: density_small,
        },
        PixelMoaHead {
            id: 2,
            family: PixelMoaFamily::Ink,
            value: density_medium,
        },
        PixelMoaHead {
            id: 8,
            family: PixelMoaFamily::Rhythm,
            value: rhythm_horizontal,
        },
        PixelMoaHead {
            id: 9,
            family: PixelMoaFamily::Rhythm,
            value: rhythm_vertical,
        },
        PixelMoaHead {
            id: 16,
            family: PixelMoaFamily::Surface,
            value: surface_owned,
        },
        PixelMoaHead {
            id: 24,
            family: PixelMoaFamily::Suppression,
            value: contour_pressure,
        },
        PixelMoaHead {
            id: 25,
            family: PixelMoaFamily::Suppression,
            value: face_mark_pressure,
        },
    ]
}

#[cfg(not(target_arch = "wasm32"))]
fn fold_pixel_moa_families(heads: &[PixelMoaHead]) -> f32 {
    let ink = fold_pixel_moa_family(heads, PixelMoaFamily::Ink);
    let rhythm = fold_pixel_moa_family(heads, PixelMoaFamily::Rhythm);
    let surface = fold_pixel_moa_family(heads, PixelMoaFamily::Surface);
    let suppression = fold_pixel_moa_family(heads, PixelMoaFamily::Suppression);
    let constructive = 0.36 * ink + 0.34 * rhythm + 0.30 * surface;
    (constructive * (1.0 - (suppression * 0.45).min(0.75))).clamp(0.0, 1.0)
}

#[cfg(not(target_arch = "wasm32"))]
fn fold_pixel_moa_family(heads: &[PixelMoaHead], family: PixelMoaFamily) -> f32 {
    let mut values = Vec::new();
    for head in heads {
        if head.id < 32 && head.family == family && head.value.is_finite() {
            values.push(head.value.clamp(0.0, 1.0));
        }
    }
    if values.is_empty() {
        return 0.0;
    }
    let mean = values.iter().sum::<f32>() / values.len() as f32;
    let disagreement = values.iter().map(|v| (v - mean).abs()).sum::<f32>() / values.len() as f32;
    (mean * (1.0 - disagreement.min(0.7))).clamp(0.0, 1.0)
}

#[cfg(not(target_arch = "wasm32"))]
fn write_f32_gray_png(path: &Path, width: u32, height: u32, values: &[f32]) -> Result<(), String> {
    if values.len() != (width * height) as usize {
        return Err("depth probe image shape mismatch".to_string());
    }
    let mut image = image::GrayImage::new(width, height);
    for (index, pixel) in image.pixels_mut().enumerate() {
        let v = (values[index].clamp(0.0, 1.0) * 255.0).round() as u8;
        *pixel = image::Luma([v]);
    }
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|e| e.to_string())?;
    }
    image
        .save(path)
        .map_err(|e| format!("save {}: {}", path.display(), e))
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_text_like_preview_iteration(
    rgba: &mut image::RgbaImage,
    config: &TextTopologyConfig,
    text_threshold: f32,
    clear_radius: u32,
    residual_threshold: f32,
    region_radius: u32,
    pixel_moa_recovery: bool,
) -> Result<u32, String> {
    let gray = image::DynamicImage::ImageRgba8(rgba.clone()).to_luma8();
    let width = gray.width() as usize;
    let height = gray.height() as usize;
    let mut ink = vec![false; width * height];
    for (i, &v) in gray.as_raw().iter().enumerate() {
        ink[i] = v <= config.ink_threshold;
    }

    let components = connected_components(&ink, width, height);
    let mut scored_components: Vec<(StrokeComponentTopology, Vec<(usize, usize)>)> = Vec::new();
    for (id, points) in components.into_iter().enumerate() {
        if points.len() < config.min_component_area as usize {
            continue;
        }
        let topology = component_topology(id as u32, &points, &ink, width, height, config);
        scored_components.push((topology, points));
    }
    let surface_boxes = bubble_like_background_surfaces(&scored_components, width, height);

    let admitted_bands = language_shaped_clear_bands(&scored_components, text_threshold);
    let mut clear_admission: Vec<Option<TextBandScore>> = vec![None; scored_components.len()];
    for (band, score) in &admitted_bands {
        for &index in band {
            clear_admission[index] = Some(score.clone());
        }
    }
    let mut cleared = 0_u32;
    for (index, admission) in clear_admission.iter().enumerate() {
        let Some(score) = admission else { continue };
        let (topology, points) = &scored_components[index];
        let fill = local_background_fill(
            rgba,
            &ink,
            topology.bbox,
            clear_radius.max(2),
            config.ink_threshold.saturating_add(90),
        );
        for &(x, y) in points {
            cleared = cleared.saturating_add(clear_around(
                rgba,
                x as u32,
                y as u32,
                clear_radius.min(8),
                fill,
            ));
        }
        if should_clear_descender_support(topology, score) {
            cleared = cleared.saturating_add(clear_descender_support(
                rgba,
                topology.bbox,
                clear_radius.min(8),
                fill,
            ));
        }
    }
    cleared = cleared.saturating_add(cleanup_text_band_artifacts(
        rgba,
        &gray,
        &ink,
        &admitted_bands,
        clear_radius.min(8),
        config.ink_threshold,
        config.ink_threshold.saturating_add(110),
    ));
    if residual_threshold <= 1.0 {
        cleared = cleared.saturating_add(clear_admitted_residual_artifacts(
            rgba,
            &ink,
            &scored_components,
            &admitted_bands,
            residual_threshold,
            clear_radius,
            config.ink_threshold.saturating_add(90),
        ));
    }
    if pixel_moa_recovery {
        cleared = cleared.saturating_add(clear_pixel_moa_band_recovery(
            rgba,
            &gray,
            &ink,
            &admitted_bands,
            &surface_boxes,
            clear_radius,
            config.ink_threshold.saturating_add(90),
        ));
    }
    if region_radius > 0 {
        cleared = cleared.saturating_add(clear_text_region_envelope(
            rgba,
            &ink,
            &scored_components,
            text_threshold,
            region_radius.min(24),
            config.ink_threshold.saturating_add(110),
        ));
        cleared = cleared.saturating_add(clear_mask_attached_text_filaments(
            rgba,
            &gray,
            &ink,
            &scored_components,
            &admitted_bands,
            &surface_boxes,
            text_threshold,
            region_radius.min(24),
            config.ink_threshold.saturating_add(110),
        ));
        cleared = cleared.saturating_add(clear_closed_text_regions(
            rgba,
            &gray,
            &ink,
            &admitted_bands,
            region_radius,
            config.ink_threshold,
            config.ink_threshold.saturating_add(110),
        ));
    }
    Ok(cleared)
}

#[cfg(not(target_arch = "wasm32"))]
fn paint_text_stroke_envelope_mask(
    mask: &mut image::GrayImage,
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
    radius: u32,
) -> u32 {
    let width = mask.width();
    let height = mask.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let surface_boxes =
        bubble_like_background_surfaces(components, width as usize, height as usize);
    let admitted_blocks = language_shaped_text_blocks(components, text_threshold, &surface_boxes);
    let mut painted = 0_u32;
    for band in admitted_blocks {
        for index in band {
            let Some((topology, points)) = components.get(index) else {
                continue;
            };
            for &(x, y) in points {
                painted = painted.saturating_add(paint_disc(mask, x as u32, y as u32, radius));
            }
            painted = painted.saturating_add(paint_descender_support(mask, topology.bbox, radius));
        }
    }
    close_mask_once(mask, radius.max(1).min(3));
    painted
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_text_region_envelope(
    image: &mut image::RgbaImage,
    ink: &[bool],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
    radius: u32,
    background_luma_min: u8,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let mut mask = image::GrayImage::new(width, height);
    let painted = paint_text_stroke_envelope_mask(&mut mask, components, text_threshold, radius);
    if painted == 0 {
        return 0;
    }
    let mut bbox: Option<[u32; 4]> = None;
    for y in 0..height {
        for x in 0..width {
            if mask.get_pixel(x, y).0[0] == 0 {
                continue;
            }
            bbox = Some(match bbox {
                Some([x0, y0, x1, y1]) => [x0.min(x), y0.min(y), x1.max(x), y1.max(y)],
                None => [x, y, x, y],
            });
        }
    }
    let Some(mask_bbox) = bbox else { return 0 };
    let fill = local_background_fill(image, ink, mask_bbox, radius.max(2), background_luma_min);
    let mut cleared = 0_u32;
    for y in 0..height {
        for x in 0..width {
            if mask.get_pixel(x, y).0[0] == 0 {
                continue;
            }
            image.put_pixel(x, y, fill);
            cleared = cleared.saturating_add(1);
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_mask_attached_text_filaments(
    image: &mut image::RgbaImage,
    gray: &image::GrayImage,
    ink: &[bool],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    bands: &[(Vec<usize>, TextBandScore)],
    surfaces: &[SurfaceBox],
    text_threshold: f32,
    radius: u32,
    background_luma_min: u8,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let mut text_mask = image::GrayImage::new(width, height);
    if paint_text_stroke_envelope_mask(&mut text_mask, components, text_threshold, radius) == 0 {
        return 0;
    }
    let mut cleared = 0_u32;
    let bridge_radius = radius.max(2).min(5);
    for (_, score) in bands {
        let [x0, y0, x1, y1] = score.bbox;
        let pad_x = (score.average_height * 1.8).max(bridge_radius as f32 + 5.0) as u32;
        let pad_y = (score.average_height * 1.3).max(bridge_radius as f32 + 4.0) as u32;
        let sx0 = x0.saturating_sub(pad_x);
        let sy0 = y0.saturating_sub(pad_y);
        let sx1 = x1.saturating_add(pad_x).min(width - 1);
        let sy1 = y1.saturating_add(pad_y).min(height - 1);
        let local_width = sx1.saturating_sub(sx0).saturating_add(1) as usize;
        let local_height = sy1.saturating_sub(sy0).saturating_add(1) as usize;
        let mut eligible = vec![false; local_width * local_height];
        for y in sy0..=sy1 {
            for x in sx0..=sx1 {
                let index = y as usize * width as usize + x as usize;
                if !ink.get(index).copied().unwrap_or(false)
                    || text_mask.get_pixel(x, y).0[0] > 0
                    || !point_near_text_mask(&text_mask, x, y, bridge_radius)
                {
                    continue;
                }
                let heads = pixel_moa_head_bank(
                    gray.get_pixel(x, y).0[0],
                    ink,
                    width as usize,
                    height as usize,
                    x as usize,
                    y as usize,
                    surfaces,
                );
                let text_prior = fold_pixel_moa_families(&heads);
                let rhythm_prior = fold_pixel_moa_family(&heads, PixelMoaFamily::Rhythm);
                let suppression_prior = fold_pixel_moa_family(&heads, PixelMoaFamily::Suppression);
                if text_prior < 0.24 || rhythm_prior < 0.22 || suppression_prior > 0.78 {
                    continue;
                }
                eligible[(y - sy0) as usize * local_width + (x - sx0) as usize] = true;
            }
        }
        let fill = local_background_fill(
            image,
            ink,
            [sx0, sy0, sx1, sy1],
            pad_x.max(2),
            background_luma_min,
        );
        let mut seen = vec![false; eligible.len()];
        for ly in 0..local_height {
            for lx in 0..local_width {
                let start = ly * local_width + lx;
                if seen[start] || !eligible[start] {
                    continue;
                }
                seen[start] = true;
                let mut queue = VecDeque::from([(lx, ly)]);
                let mut points = Vec::new();
                let mut min_x = u32::MAX;
                let mut min_y = u32::MAX;
                let mut max_x = 0_u32;
                let mut max_y = 0_u32;
                let mut mask_touch_count = 0_u32;
                while let Some((cx, cy)) = queue.pop_front() {
                    let x = sx0 + cx as u32;
                    let y = sy0 + cy as u32;
                    min_x = min_x.min(x);
                    min_y = min_y.min(y);
                    max_x = max_x.max(x);
                    max_y = max_y.max(y);
                    if point_near_text_mask(&text_mask, x, y, 1) {
                        mask_touch_count = mask_touch_count.saturating_add(1);
                    }
                    points.push((x, y));
                    for (nx, ny) in neighbors4(cx, cy, local_width, local_height) {
                        let ni = ny * local_width + nx;
                        if seen[ni] || !eligible[ni] {
                            continue;
                        }
                        seen[ni] = true;
                        queue.push_back((nx, ny));
                    }
                }
                if !is_mask_attached_text_filament(
                    &points,
                    [min_x, min_y, max_x, max_y],
                    score,
                    mask_touch_count,
                ) {
                    continue;
                }
                for (x, y) in points {
                    cleared =
                        cleared.saturating_add(clear_around(image, x, y, radius.min(4), fill));
                }
            }
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn point_near_text_mask(mask: &image::GrayImage, x: u32, y: u32, radius: u32) -> bool {
    let width = mask.width();
    let height = mask.height();
    let sx0 = x.saturating_sub(radius);
    let sy0 = y.saturating_sub(radius);
    let sx1 = x.saturating_add(radius).min(width.saturating_sub(1));
    let sy1 = y.saturating_add(radius).min(height.saturating_sub(1));
    for cy in sy0..=sy1 {
        for cx in sx0..=sx1 {
            if mask.get_pixel(cx, cy).0[0] > 0 {
                return true;
            }
        }
    }
    false
}

#[cfg(not(target_arch = "wasm32"))]
fn is_mask_attached_text_filament(
    points: &[(u32, u32)],
    bbox: [u32; 4],
    score: &TextBandScore,
    mask_touch_count: u32,
) -> bool {
    if points.len() < 2 || points.len() > 120 || mask_touch_count == 0 {
        return false;
    }
    let [x0, y0, x1, y1] = bbox;
    let width = x1.saturating_sub(x0).saturating_add(1);
    let height = y1.saturating_sub(y0).saturating_add(1);
    let line_height = score.average_height.max(1.0);
    let center_x = (x0 + x1) as f32 * 0.5;
    let center_y = (y0 + y1) as f32 * 0.5;
    let [bx0, by0, bx1, by1] = score.bbox;
    let x_margin = (line_height * 1.8).max(12.0);
    let y_margin = (line_height * 1.4).max(9.0);
    let near_band = center_x >= bx0 as f32 - x_margin
        && center_x <= bx1 as f32 + x_margin
        && center_y >= by0 as f32 - y_margin
        && center_y <= by1 as f32 + y_margin;
    near_band
        && width <= (line_height * 1.4).max(12.0) as u32
        && height <= (line_height * 2.0).max(18.0) as u32
        && mask_touch_count as f32 / points.len() as f32 >= 0.08
}

#[cfg(not(target_arch = "wasm32"))]
fn language_shaped_text_blocks(
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
    surface_boxes: &[SurfaceBox],
) -> Vec<Vec<usize>> {
    let blocks = glyph_paragraph_blocks(components, text_threshold);
    let admitted: Vec<_> = blocks
        .into_iter()
        .filter_map(|block| language_shaped_block_rows(&block, components, surface_boxes))
        .flatten()
        .collect();
    if !admitted.is_empty() {
        return admitted;
    }

    let admitted_bands = language_shaped_clear_bands(components, text_threshold);
    if admitted_bands.is_empty() {
        return Vec::new();
    }
    let mut parent: Vec<usize> = (0..admitted_bands.len()).collect();
    for i in 0..admitted_bands.len() {
        for j in (i + 1)..admitted_bands.len() {
            if bands_are_paragraph_neighbors(&admitted_bands[i].1, &admitted_bands[j].1) {
                union(&mut parent, i, j);
            }
        }
    }

    let mut blocks: Vec<(usize, Vec<usize>)> = Vec::new();
    for (band_index, (band, _)) in admitted_bands.iter().enumerate() {
        let root = find(&mut parent, band_index);
        if let Some((_, block)) = blocks
            .iter_mut()
            .find(|(block_root, _)| *block_root == root)
        {
            block.extend(band.iter().copied());
        } else {
            blocks.push((root, band.clone()));
        }
    }
    blocks.into_iter().map(|(_, block)| block).collect()
}

#[cfg(not(target_arch = "wasm32"))]
fn glyph_paragraph_blocks(
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
) -> Vec<Vec<usize>> {
    let mut glyphs: Vec<usize> = components
        .iter()
        .enumerate()
        .filter_map(|(index, (component, _))| {
            if is_glyph_sized(component, text_threshold) {
                Some(index)
            } else {
                None
            }
        })
        .collect();
    glyphs.sort_by_key(|&index| components[index].0.bbox[1]);
    let mut parent: Vec<usize> = (0..glyphs.len()).collect();
    for i in 0..glyphs.len() {
        for j in (i + 1)..glyphs.len() {
            if glyphs_are_paragraph_neighbors(&components[glyphs[i]].0, &components[glyphs[j]].0) {
                union(&mut parent, i, j);
            }
        }
    }
    let mut blocks: Vec<(usize, Vec<usize>)> = Vec::new();
    for (local_index, &component_index) in glyphs.iter().enumerate() {
        let root = find(&mut parent, local_index);
        if let Some((_, block)) = blocks
            .iter_mut()
            .find(|(block_root, _)| *block_root == root)
        {
            block.push(component_index);
        } else {
            blocks.push((root, vec![component_index]));
        }
    }
    blocks.into_iter().map(|(_, block)| block).collect()
}

#[cfg(not(target_arch = "wasm32"))]
fn glyphs_are_paragraph_neighbors(
    a: &StrokeComponentTopology,
    b: &StrokeComponentTopology,
) -> bool {
    let [ax0, ay0, ax1, ay1] = a.bbox;
    let [bx0, by0, bx1, by1] = b.bbox;
    let ah = (ay1 - ay0 + 1).max(1) as f32;
    let bh = (by1 - by0 + 1).max(1) as f32;
    let horizontal_gap = if ax1 < bx0 {
        bx0 - ax1
    } else { ax0.saturating_sub(bx1) };
    let vertical_gap = if ay1 < by0 {
        by0 - ay1
    } else { ay0.saturating_sub(by1) };
    horizontal_gap <= 84 && vertical_gap <= (ah.max(bh) * 1.8).max(18.0) as u32
}

#[cfg(not(target_arch = "wasm32"))]
fn is_language_shaped_text_block(
    block: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> bool {
    if block.len() < 6 {
        return false;
    }
    if !block_contains_line_rhythm(block, components) {
        return false;
    }
    let mut min_x = u32::MAX;
    let mut min_y = u32::MAX;
    let mut max_x = 0_u32;
    let mut max_y = 0_u32;
    let mut high_confidence = 0_usize;
    let mut total_text_likeness = 0.0_f32;
    for &index in block {
        let component = &components[index].0;
        let [x0, y0, x1, y1] = component.bbox;
        min_x = min_x.min(x0);
        min_y = min_y.min(y0);
        max_x = max_x.max(x1);
        max_y = max_y.max(y1);
        total_text_likeness += component.text_likeness;
        if component.text_likeness >= 0.7 {
            high_confidence += 1;
        }
    }
    let width = max_x.saturating_sub(min_x).saturating_add(1);
    let height = max_y.saturating_sub(min_y).saturating_add(1);
    let average_text_likeness = total_text_likeness / block.len() as f32;
    high_confidence >= 3
        && average_text_likeness >= 0.62
        && width >= 36
        && height >= 12
        && width <= 360
        && height <= 180
}

#[cfg(not(target_arch = "wasm32"))]
fn language_shaped_block_rows(
    block: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    surface_boxes: &[SurfaceBox],
) -> Option<Vec<Vec<usize>>> {
    if !is_language_shaped_text_block(block, components) {
        return None;
    }
    let rows = block_rhythm_rows(block, components, surface_boxes);
    if rows.is_empty() {
        return None;
    }
    Some(rows)
}

#[cfg(not(target_arch = "wasm32"))]
fn block_contains_line_rhythm(
    block: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> bool {
    !block_rhythm_rows(block, components, &[]).is_empty()
}

#[cfg(not(target_arch = "wasm32"))]
fn block_rhythm_rows(
    block: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    surface_boxes: &[SurfaceBox],
) -> Vec<Vec<usize>> {
    let mut sorted = block.to_vec();
    sorted.sort_by_key(|&index| {
        let bbox = components[index].0.bbox;
        (bbox[1] + bbox[3]) / 2
    });

    let mut rows: Vec<Vec<usize>> = Vec::new();
    for index in sorted {
        let component = &components[index].0;
        let center_y = (component.bbox[1] + component.bbox[3]) as f32 * 0.5;
        if let Some(row) = rows.iter_mut().find(|row| {
            let first = &components[row[0]].0;
            let first_center_y = (first.bbox[1] + first.bbox[3]) as f32 * 0.5;
            let height = (first.bbox[3] - first.bbox[1] + 1)
                .max(component.bbox[3] - component.bbox[1] + 1) as f32;
            (center_y - first_center_y).abs() <= (height * 1.35).max(10.0)
        }) {
            row.push(index);
        } else {
            rows.push(vec![index]);
        }
    }

    rows.into_iter()
        .filter_map(|mut row| {
            if row.len() < 4 {
                return None;
            }
            row.sort_by_key(|&index| components[index].0.bbox[0]);
            score_language_band_candidate(&row, components).and_then(|score| {
                let strong_rhythm = score.band.compact_gap_ratio >= 0.55
                    && score.band.band_width >= (score.band.average_height * 3.5).max(28.0) as u32
                    && score.band.high_confidence >= 1;
                let surface_owned = text_band_has_surface_owner(&score.band, surface_boxes)
                    && score.band.compact_gap_ratio >= 0.35
                    && score.band.high_confidence >= 1;
                (strong_rhythm || surface_owned).then_some(row)
            })
        })
        .collect()
}

#[cfg(not(target_arch = "wasm32"))]
#[derive(Clone, Debug)]
struct SurfaceBox {
    bbox: [u32; 4],
    area: u32,
    interior: Vec<bool>,
}

#[cfg(not(target_arch = "wasm32"))]
fn text_band_has_surface_owner(score: &TextBandScore, surfaces: &[SurfaceBox]) -> bool {
    surfaces
        .iter()
        .any(|surface| surface_supports_text_band(surface, score))
}

#[cfg(not(target_arch = "wasm32"))]
fn surface_supports_text_band(surface: &SurfaceBox, score: &TextBandScore) -> bool {
    let [sx0, sy0, sx1, sy1] = surface.bbox;
    let [x0, y0, x1, y1] = score.bbox;
    let pad_x = (score.average_height * 1.5).max(8.0) as u32;
    let pad_y = (score.average_height * 1.2).max(6.0) as u32;
    x0 >= sx0.saturating_sub(pad_x)
        && x1 <= sx1.saturating_add(pad_x)
        && y0 >= sy0.saturating_sub(pad_y)
        && y1 <= sy1.saturating_add(pad_y)
        && surface.area
            >= score
                .band_width
                .saturating_mul(score.average_height.max(1.0) as u32)
}

#[cfg(not(target_arch = "wasm32"))]
fn point_in_surface_interior(surface: &SurfaceBox, x: u32, y: u32) -> bool {
    let [x0, y0, x1, y1] = surface.bbox;
    if x <= x0.saturating_add(2)
        || x >= x1.saturating_sub(2)
        || y <= y0.saturating_add(2)
        || y >= y1.saturating_sub(2)
    {
        return false;
    }
    let local_width = x1.saturating_sub(x0).saturating_add(1) as usize;
    let local_x = x.saturating_sub(x0) as usize;
    let local_y = y.saturating_sub(y0) as usize;
    surface
        .interior
        .get(local_y * local_width + local_x)
        .copied()
        .unwrap_or(false)
}

#[cfg(not(target_arch = "wasm32"))]
fn point_in_erodable_surface_interior(surface: &SurfaceBox, x: u32, y: u32, erosion: u32) -> bool {
    if !point_in_surface_interior(surface, x, y) {
        return false;
    }
    let [x0, y0, x1, y1] = surface.bbox;
    let sx0 = x.saturating_sub(erosion).max(x0);
    let sy0 = y.saturating_sub(erosion).max(y0);
    let sx1 = x.saturating_add(erosion).min(x1);
    let sy1 = y.saturating_add(erosion).min(y1);
    for cy in sy0..=sy1 {
        for cx in sx0..=sx1 {
            if !point_in_surface_interior(surface, cx, cy) {
                return false;
            }
        }
    }
    true
}

#[cfg(not(target_arch = "wasm32"))]
fn point_has_erodable_surface_support(
    surface: &SurfaceBox,
    x: u32,
    y: u32,
    support_radius: u32,
    erosion: u32,
) -> bool {
    let [x0, y0, x1, y1] = surface.bbox;
    let sx0 = x.saturating_sub(support_radius).max(x0);
    let sy0 = y.saturating_sub(support_radius).max(y0);
    let sx1 = x.saturating_add(support_radius).min(x1);
    let sy1 = y.saturating_add(support_radius).min(y1);
    for cy in sy0..=sy1 {
        for cx in sx0..=sx1 {
            if point_in_erodable_surface_interior(surface, cx, cy, erosion) {
                return true;
            }
        }
    }
    false
}

#[cfg(not(target_arch = "wasm32"))]
fn point_surface_support_directions(
    surface: &SurfaceBox,
    x: u32,
    y: u32,
    offset: u32,
    erosion: u32,
) -> u8 {
    let probes = [
        (x.saturating_sub(offset), y),
        (x.saturating_add(offset), y),
        (x, y.saturating_sub(offset)),
        (x, y.saturating_add(offset)),
    ];
    probes
        .into_iter()
        .filter(|&(px, py)| point_in_erodable_surface_interior(surface, px, py, erosion))
        .count() as u8
}

#[cfg(not(target_arch = "wasm32"))]
fn bubble_like_background_surfaces(
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    width: usize,
    height: usize,
) -> Vec<SurfaceBox> {
    if width == 0 || height == 0 {
        return Vec::new();
    }
    let mut ink = vec![false; width * height];
    for (_, points) in components {
        for &(x, y) in points {
            if x < width && y < height {
                ink[y * width + x] = true;
            }
        }
    }

    let mut seen = vec![false; width * height];
    let mut surfaces = Vec::new();
    for y in 0..height {
        for x in 0..width {
            let index = y * width + x;
            if seen[index] || ink[index] {
                continue;
            }
            seen[index] = true;
            let mut queue = VecDeque::from([(x, y)]);
            let mut area = 0_u32;
            let mut touches_edge = false;
            let mut min_x = x;
            let mut max_x = x;
            let mut min_y = y;
            let mut max_y = y;
            let mut pixels = Vec::new();
            while let Some((cx, cy)) = queue.pop_front() {
                pixels.push((cx, cy));
                area = area.saturating_add(1);
                touches_edge =
                    touches_edge || cx == 0 || cy == 0 || cx + 1 == width || cy + 1 == height;
                min_x = min_x.min(cx);
                max_x = max_x.max(cx);
                min_y = min_y.min(cy);
                max_y = max_y.max(cy);
                for (nx, ny) in neighbors4(cx, cy, width, height) {
                    let ni = ny * width + nx;
                    if seen[ni] || ink[ni] {
                        continue;
                    }
                    seen[ni] = true;
                    queue.push_back((nx, ny));
                }
            }
            let bw = max_x - min_x + 1;
            let bh = max_y - min_y + 1;
            let aspect = bw as f32 / bh.max(1) as f32;
            if !touches_edge && area >= 700 && bw >= 45 && bh >= 22 && aspect >= 1.05 {
                let mut interior = vec![false; bw * bh];
                for (px, py) in pixels {
                    interior[(py - min_y) * bw + (px - min_x)] = true;
                }
                surfaces.push(SurfaceBox {
                    bbox: [min_x as u32, min_y as u32, max_x as u32, max_y as u32],
                    area,
                    interior,
                });
            }
        }
    }
    surfaces
}

#[cfg(not(target_arch = "wasm32"))]
fn local_ink_density(
    ink: &[bool],
    width: usize,
    height: usize,
    x: usize,
    y: usize,
    radius: usize,
) -> f32 {
    let x0 = x.saturating_sub(radius);
    let y0 = y.saturating_sub(radius);
    let x1 = (x + radius).min(width - 1);
    let y1 = (y + radius).min(height - 1);
    let mut count = 0_u32;
    let mut total = 0_u32;
    for cy in y0..=y1 {
        for cx in x0..=x1 {
            total = total.saturating_add(1);
            if ink[cy * width + cx] {
                count = count.saturating_add(1);
            }
        }
    }
    count as f32 / total.max(1) as f32
}

#[cfg(not(target_arch = "wasm32"))]
fn local_horizontal_rhythm(ink: &[bool], width: usize, height: usize, x: usize, y: usize) -> f32 {
    let y0 = y.saturating_sub(2);
    let y1 = (y + 2).min(height - 1);
    let x0 = x.saturating_sub(18);
    let x1 = (x + 18).min(width - 1);
    let mut runs = 0_u32;
    let mut ink_pixels = 0_u32;
    for cy in y0..=y1 {
        let mut in_run = false;
        for cx in x0..=x1 {
            let is_ink = ink[cy * width + cx];
            if is_ink {
                ink_pixels = ink_pixels.saturating_add(1);
            }
            if is_ink && !in_run {
                runs = runs.saturating_add(1);
                in_run = true;
            } else if !is_ink {
                in_run = false;
            }
        }
    }
    let density = ink_pixels as f32 / (((x1 - x0 + 1) * (y1 - y0 + 1)) as f32).max(1.0);
    let cadence = (runs as f32 / 10.0).min(1.0);
    (0.65 * cadence + 0.35 * (1.0 - (density - 0.22).abs() / 0.22).clamp(0.0, 1.0)).clamp(0.0, 1.0)
}

#[cfg(not(target_arch = "wasm32"))]
fn local_vertical_rhythm(ink: &[bool], width: usize, height: usize, x: usize, y: usize) -> f32 {
    let x0 = x.saturating_sub(2);
    let x1 = (x + 2).min(width - 1);
    let y0 = y.saturating_sub(18);
    let y1 = (y + 18).min(height - 1);
    let mut runs = 0_u32;
    let mut ink_pixels = 0_u32;
    for cx in x0..=x1 {
        let mut in_run = false;
        for cy in y0..=y1 {
            let is_ink = ink[cy * width + cx];
            if is_ink {
                ink_pixels = ink_pixels.saturating_add(1);
            }
            if is_ink && !in_run {
                runs = runs.saturating_add(1);
                in_run = true;
            } else if !is_ink {
                in_run = false;
            }
        }
    }
    let density = ink_pixels as f32 / (((x1 - x0 + 1) * (y1 - y0 + 1)) as f32).max(1.0);
    let cadence = (runs as f32 / 10.0).min(1.0);
    (0.55 * cadence + 0.45 * (1.0 - (density - 0.18).abs() / 0.18).clamp(0.0, 1.0)).clamp(0.0, 1.0)
}

fn bands_are_paragraph_neighbors(a: &TextBandScore, b: &TextBandScore) -> bool {
    let [ax0, ay0, ax1, ay1] = a.bbox;
    let [bx0, by0, bx1, by1] = b.bbox;
    let vertical_gap = if ay1 < by0 {
        by0 - ay1
    } else { ay0.saturating_sub(by1) };
    let horizontal_overlap = ax1.min(bx1).saturating_sub(ax0.max(bx0));
    let min_width = a.band_width.min(b.band_width).max(1);
    let close_vertically = vertical_gap <= (a.average_height.max(b.average_height) * 2.4) as u32;
    let aligned = horizontal_overlap as f32 / min_width as f32 >= 0.18
        || ax0.abs_diff(bx0) <= (a.average_height.max(b.average_height) * 3.0) as u32;
    close_vertically && aligned
}

#[cfg(not(target_arch = "wasm32"))]
fn paint_descender_support(mask: &mut image::GrayImage, bbox: [u32; 4], radius: u32) -> u32 {
    let width = mask.width();
    let height = mask.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let [x0, y0, x1, y1] = bbox;
    let component_h = y1.saturating_sub(y0).saturating_add(1);
    if component_h < 12 {
        return 0;
    }
    let mid_x = (x0 + x1) / 2;
    let stem_radius = radius.max(2).min(10);
    let support_top = y0.saturating_add(component_h / 2);
    let support_bottom = y1.saturating_add(stem_radius).min(height - 1);
    let mut painted = 0_u32;
    for y in support_top..=support_bottom {
        painted = painted.saturating_add(paint_disc(mask, mid_x, y, stem_radius));
    }
    if x1 > x0 + 3 {
        for offset in 0..=stem_radius {
            let y = support_top.saturating_add(offset).min(height - 1);
            let left_x = mid_x.saturating_sub(offset);
            let right_x = mid_x.saturating_add(offset).min(width - 1);
            painted = painted.saturating_add(paint_disc(mask, left_x, y, radius.max(1).min(5)));
            painted = painted.saturating_add(paint_disc(mask, right_x, y, radius.max(1).min(5)));
        }
    }
    painted
}

#[cfg(not(target_arch = "wasm32"))]
fn should_clear_descender_support(
    component: &StrokeComponentTopology,
    line: &TextBandScore,
) -> bool {
    let [x0, y0, x1, y1] = component.bbox;
    let width = x1.saturating_sub(x0).saturating_add(1);
    let height = y1.saturating_sub(y0).saturating_add(1);
    let center_y = (y0 + y1) / 2;
    let line_height = line.average_height.max(1.0);
    component.text_likeness >= 0.72
        && component.area <= 120
        && height >= 12
        && width <= (line_height * 0.85).max(8.0) as u32
        && height <= (line_height * 2.2).max(18.0) as u32
        && center_y >= line.bbox[1].saturating_sub(line_height as u32)
        && center_y <= line.bbox[3].saturating_add(line_height as u32)
        && line.language_shape_score >= 0.45
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_descender_support(
    image: &mut image::RgbaImage,
    bbox: [u32; 4],
    radius: u32,
    fill: image::Rgba<u8>,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let [x0, y0, x1, y1] = bbox;
    let component_h = y1.saturating_sub(y0).saturating_add(1);
    if component_h < 12 {
        return 0;
    }
    let mid_x = (x0 + x1) / 2;
    let stem_radius = radius.max(2).min(10);
    let support_top = y0.saturating_add(component_h / 2);
    let support_bottom = y1.saturating_add(stem_radius).min(height - 1);
    let mut cleared = 0_u32;
    for y in support_top..=support_bottom {
        cleared = cleared.saturating_add(clear_around(image, mid_x, y, stem_radius, fill));
    }
    if x1 > x0 + 3 {
        for offset in 0..=stem_radius {
            let y = support_top.saturating_add(offset).min(height - 1);
            let left_x = mid_x.saturating_sub(offset);
            let right_x = mid_x.saturating_add(offset).min(width - 1);
            cleared =
                cleared.saturating_add(clear_around(image, left_x, y, radius.max(1).min(5), fill));
            cleared =
                cleared.saturating_add(clear_around(image, right_x, y, radius.max(1).min(5), fill));
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn paint_disc(mask: &mut image::GrayImage, x: u32, y: u32, radius: u32) -> u32 {
    let width = mask.width();
    let height = mask.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let radius = radius.max(1).min(24);
    let r2 = (radius * radius) as i32;
    let x0 = x.saturating_sub(radius);
    let y0 = y.saturating_sub(radius);
    let x1 = x.saturating_add(radius).min(width - 1);
    let y1 = y.saturating_add(radius).min(height - 1);
    let mut painted = 0_u32;
    for cy in y0..=y1 {
        for cx in x0..=x1 {
            let dx = cx as i32 - x as i32;
            let dy = cy as i32 - y as i32;
            if dx * dx + dy * dy > r2 {
                continue;
            }
            if mask.get_pixel(cx, cy).0[0] == 0 {
                painted = painted.saturating_add(1);
            }
            mask.put_pixel(cx, cy, image::Luma([255]));
        }
    }
    painted
}

#[cfg(not(target_arch = "wasm32"))]
fn close_mask_once(mask: &mut image::GrayImage, radius: u32) {
    let width = mask.width();
    let height = mask.height();
    if width == 0 || height == 0 {
        return;
    }
    let source = mask.clone();
    for y in 0..height {
        for x in 0..width {
            if source.get_pixel(x, y).0[0] > 0 {
                continue;
            }
            let x0 = x.saturating_sub(radius);
            let y0 = y.saturating_sub(radius);
            let x1 = x.saturating_add(radius).min(width - 1);
            let y1 = y.saturating_add(radius).min(height - 1);
            let mut horizontal = false;
            let mut vertical = false;
            for cx in x0..=x1 {
                if source.get_pixel(cx, y).0[0] > 0 {
                    horizontal = true;
                    break;
                }
            }
            for cy in y0..=y1 {
                if source.get_pixel(x, cy).0[0] > 0 {
                    vertical = true;
                    break;
                }
            }
            if horizontal && vertical {
                mask.put_pixel(x, y, image::Luma([255]));
            }
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_closed_text_regions(
    image: &mut image::RgbaImage,
    gray: &image::GrayImage,
    ink: &[bool],
    bands: &[(Vec<usize>, TextBandScore)],
    region_radius: u32,
    primary_ink_luma_max: u8,
    artifact_luma_max: u8,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let mut cleared = 0_u32;
    for (_, score) in bands {
        let [x0, y0, x1, y1] = score.bbox;
        let region_pad_x = region_radius
            .saturating_add((score.average_height * 0.35) as u32)
            .min(32);
        let region_pad_y = region_radius
            .saturating_add((score.average_height * 0.2) as u32)
            .min(24);
        let sx0 = x0.saturating_sub(region_pad_x);
        let sy0 = y0.saturating_sub(region_pad_y);
        let sx1 = x1.saturating_add(region_pad_x).min(width - 1);
        let sy1 = y1.saturating_add(region_pad_y).min(height - 1);
        let fill = local_background_fill(
            image,
            ink,
            [sx0, sy0, sx1, sy1],
            region_pad_x.max(2),
            artifact_luma_max,
        );
        for y in sy0..=sy1 {
            for x in sx0..=sx1 {
                let luma = gray.get_pixel(x, y).0[0];
                let index = y as usize * width as usize + x as usize;
                if luma <= artifact_luma_max
                    && luma > primary_ink_luma_max.saturating_sub(20)
                    && !ink.get(index).copied().unwrap_or(false)
                {
                    image.put_pixel(x, y, fill);
                    cleared = cleared.saturating_add(1);
                }
            }
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_admitted_residual_artifacts(
    image: &mut image::RgbaImage,
    ink: &[bool],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    bands: &[(Vec<usize>, TextBandScore)],
    residual_threshold: f32,
    radius: u32,
    background_luma_min: u8,
) -> u32 {
    let mut cleared = 0_u32;
    for (band, score) in bands {
        let mut admitted = vec![false; components.len()];
        for &index in band {
            admitted[index] = true;
        }
        for (index, (component, points)) in components.iter().enumerate() {
            if admitted[index]
                || !is_residual_text_artifact(component, score)
                    && !is_kmeans_band_attached_residual(component, band, components, score)
            {
                continue;
            }
            let admission_score = residual_attachment_score(component, score);
            if admission_score < residual_threshold {
                continue;
            }
            let fill = local_background_fill(
                image,
                ink,
                component.bbox,
                radius.max(2),
                background_luma_min,
            );
            for &(x, y) in points {
                cleared = cleared.saturating_add(clear_around(
                    image,
                    x as u32,
                    y as u32,
                    radius.min(8),
                    fill,
                ));
            }
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_pixel_moa_band_recovery(
    image: &mut image::RgbaImage,
    gray: &image::GrayImage,
    ink: &[bool],
    bands: &[(Vec<usize>, TextBandScore)],
    surfaces: &[SurfaceBox],
    radius: u32,
    background_luma_min: u8,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let mut cleared = 0_u32;
    for (_, score) in bands {
        let supporting_surface = surfaces
            .iter()
            .find(|surface| surface_supports_text_band(surface, score));
        let Some(surface) = supporting_surface else {
            continue;
        };
        let [x0, y0, x1, y1] = score.bbox;
        let pad_x = (score.average_height * 1.8).max(radius as f32 + 5.0) as u32;
        let pad_y = (score.average_height * 1.2).max(radius as f32 + 3.0) as u32;
        let sx0 = x0.saturating_sub(pad_x);
        let sy0 = y0.saturating_sub(pad_y);
        let sx1 = x1.saturating_add(pad_x).min(width - 1);
        let sy1 = y1.saturating_add(pad_y).min(height - 1);
        let fill = local_background_fill(
            image,
            ink,
            [sx0, sy0, sx1, sy1],
            pad_x.max(2),
            background_luma_min,
        );
        let local_width = sx1.saturating_sub(sx0).saturating_add(1) as usize;
        let local_height = sy1.saturating_sub(sy0).saturating_add(1) as usize;
        let mut eligible = vec![false; local_width * local_height];
        for y in sy0..=sy1 {
            for x in sx0..=sx1 {
                let index = y as usize * width as usize + x as usize;
                if !ink.get(index).copied().unwrap_or(false) {
                    continue;
                }
                if !point_has_erodable_surface_support(
                    surface,
                    x,
                    y,
                    radius.max(2).min(4),
                    radius.max(2).min(4),
                ) {
                    continue;
                }
                eligible[(y - sy0) as usize * local_width + (x - sx0) as usize] = true;
            }
        }
        let mut seen = vec![false; eligible.len()];
        for ly in 0..local_height {
            for lx in 0..local_width {
                let start = ly * local_width + lx;
                if seen[start] || !eligible[start] {
                    continue;
                }
                seen[start] = true;
                let mut queue = VecDeque::from([(lx, ly)]);
                let mut points = Vec::new();
                let mut min_x = u32::MAX;
                let mut min_y = u32::MAX;
                let mut max_x = 0_u32;
                let mut max_y = 0_u32;
                let mut text_prior_sum = 0.0_f32;
                let mut rhythm_prior_sum = 0.0_f32;
                let mut suppression_prior_sum = 0.0_f32;
                let mut support_direction_sum = 0_u32;
                while let Some((cx, cy)) = queue.pop_front() {
                    let x = sx0 + cx as u32;
                    let y = sy0 + cy as u32;
                    min_x = min_x.min(x);
                    min_y = min_y.min(y);
                    max_x = max_x.max(x);
                    max_y = max_y.max(y);
                    points.push((x, y));
                    let heads = pixel_moa_head_bank(
                        gray.get_pixel(x, y).0[0],
                        ink,
                        width as usize,
                        height as usize,
                        x as usize,
                        y as usize,
                        surfaces,
                    );
                    text_prior_sum += fold_pixel_moa_families(&heads);
                    rhythm_prior_sum += fold_pixel_moa_family(&heads, PixelMoaFamily::Rhythm);
                    suppression_prior_sum +=
                        fold_pixel_moa_family(&heads, PixelMoaFamily::Suppression);
                    support_direction_sum = support_direction_sum.saturating_add(
                        point_surface_support_directions(surface, x, y, radius.max(2).min(5), 2)
                            as u32,
                    );
                    for (nx, ny) in neighbors4(cx, cy, local_width, local_height) {
                        let ni = ny * local_width + nx;
                        if seen[ni] || !eligible[ni] {
                            continue;
                        }
                        seen[ni] = true;
                        queue.push_back((nx, ny));
                    }
                }
                if !is_surface_clipped_text_fragment(
                    &points,
                    [min_x, min_y, max_x, max_y],
                    score,
                    text_prior_sum,
                    rhythm_prior_sum,
                    suppression_prior_sum,
                    support_direction_sum,
                ) {
                    continue;
                }
                for (x, y) in points {
                    cleared =
                        cleared.saturating_add(clear_around(image, x, y, radius.min(5), fill));
                }
            }
        }
    }
    cleared
}

#[cfg(not(target_arch = "wasm32"))]
fn paint_surface_fragment_probe_values(
    luma: &[u8],
    ink: &[bool],
    width: usize,
    height: usize,
    bands: &[(Vec<usize>, TextBandScore)],
    surfaces: &[SurfaceBox],
    values: &mut [f32],
) {
    for (_, score) in bands {
        let supporting_surface = surfaces
            .iter()
            .find(|surface| surface_supports_text_band(surface, score));
        let Some(surface) = supporting_surface else {
            continue;
        };
        let [x0, y0, x1, y1] = score.bbox;
        let pad_x = (score.average_height * 1.8).max(7.0) as u32;
        let pad_y = (score.average_height * 1.2).max(5.0) as u32;
        let sx0 = x0.saturating_sub(pad_x);
        let sy0 = y0.saturating_sub(pad_y);
        let sx1 = x1.saturating_add(pad_x).min(width as u32 - 1);
        let sy1 = y1.saturating_add(pad_y).min(height as u32 - 1);
        let local_width = sx1.saturating_sub(sx0).saturating_add(1) as usize;
        let local_height = sy1.saturating_sub(sy0).saturating_add(1) as usize;
        let mut eligible = vec![false; local_width * local_height];
        for y in sy0..=sy1 {
            for x in sx0..=sx1 {
                let index = y as usize * width + x as usize;
                eligible[(y - sy0) as usize * local_width + (x - sx0) as usize] =
                    ink.get(index).copied().unwrap_or(false)
                        && point_has_erodable_surface_support(surface, x, y, 3, 2);
            }
        }
        let mut seen = vec![false; eligible.len()];
        for ly in 0..local_height {
            for lx in 0..local_width {
                let start = ly * local_width + lx;
                if seen[start] || !eligible[start] {
                    continue;
                }
                seen[start] = true;
                let mut queue = VecDeque::from([(lx, ly)]);
                let mut points = Vec::new();
                let mut min_x = u32::MAX;
                let mut min_y = u32::MAX;
                let mut max_x = 0_u32;
                let mut max_y = 0_u32;
                let mut text_prior_sum = 0.0_f32;
                let mut rhythm_prior_sum = 0.0_f32;
                let mut suppression_prior_sum = 0.0_f32;
                let mut support_direction_sum = 0_u32;
                while let Some((cx, cy)) = queue.pop_front() {
                    let x = sx0 + cx as u32;
                    let y = sy0 + cy as u32;
                    min_x = min_x.min(x);
                    min_y = min_y.min(y);
                    max_x = max_x.max(x);
                    max_y = max_y.max(y);
                    points.push((x, y));
                    let image_index = y as usize * width + x as usize;
                    let heads = pixel_moa_head_bank(
                        luma[image_index],
                        ink,
                        width,
                        height,
                        x as usize,
                        y as usize,
                        surfaces,
                    );
                    text_prior_sum += fold_pixel_moa_families(&heads);
                    rhythm_prior_sum += fold_pixel_moa_family(&heads, PixelMoaFamily::Rhythm);
                    suppression_prior_sum +=
                        fold_pixel_moa_family(&heads, PixelMoaFamily::Suppression);
                    support_direction_sum = support_direction_sum.saturating_add(
                        point_surface_support_directions(surface, x, y, 3, 2) as u32,
                    );
                    for (nx, ny) in neighbors4(cx, cy, local_width, local_height) {
                        let ni = ny * local_width + nx;
                        if seen[ni] || !eligible[ni] {
                            continue;
                        }
                        seen[ni] = true;
                        queue.push_back((nx, ny));
                    }
                }
                let accepted = is_surface_clipped_text_fragment(
                    &points,
                    [min_x, min_y, max_x, max_y],
                    score,
                    text_prior_sum,
                    rhythm_prior_sum,
                    suppression_prior_sum,
                    support_direction_sum,
                );
                let value = if accepted { 1.0 } else { 0.32 };
                for (x, y) in points {
                    values[y as usize * width + x as usize] =
                        values[y as usize * width + x as usize].max(value);
                }
            }
        }
    }
}

#[cfg(not(target_arch = "wasm32"))]
fn is_surface_clipped_text_fragment(
    points: &[(u32, u32)],
    bbox: [u32; 4],
    score: &TextBandScore,
    text_prior_sum: f32,
    rhythm_prior_sum: f32,
    suppression_prior_sum: f32,
    support_direction_sum: u32,
) -> bool {
    if points.len() < 2 || points.len() > 420 {
        return false;
    }
    let [x0, y0, x1, y1] = bbox;
    let width = x1.saturating_sub(x0).saturating_add(1);
    let height = y1.saturating_sub(y0).saturating_add(1);
    if width > (score.average_height * 4.5).max(28.0) as u32
        || height > (score.average_height * 3.2).max(22.0) as u32
    {
        return false;
    }
    let count = points.len() as f32;
    let text_prior = text_prior_sum / count;
    let rhythm_prior = rhythm_prior_sum / count;
    let suppression_prior = suppression_prior_sum / count;
    let support_directions = support_direction_sum as f32 / count;
    let center_x = (x0 + x1) as f32 * 0.5;
    let center_y = (y0 + y1) as f32 * 0.5;
    let [bx0, by0, bx1, by1] = score.bbox;
    let x_margin = (score.average_height * 2.4).max(14.0);
    let y_margin = (score.average_height * 1.7).max(10.0);
    let near_band = center_x >= bx0 as f32 - x_margin
        && center_x <= bx1 as f32 + x_margin
        && center_y >= by0 as f32 - y_margin
        && center_y <= by1 as f32 + y_margin;
    let punctuation_like = points.len() <= 36
        && width <= (score.average_height * 0.95).max(8.0) as u32
        && height <= (score.average_height * 1.35).max(10.0) as u32
        && near_band
        && text_prior >= 0.22
        && suppression_prior <= 0.62;
    let glyph_like = near_band
        && text_prior >= 0.30
        && rhythm_prior >= 0.38
        && suppression_prior <= 0.55
        && support_directions >= 1.6;
    punctuation_like || glyph_like
}

#[cfg(not(target_arch = "wasm32"))]
fn cleanup_text_band_artifacts(
    image: &mut image::RgbaImage,
    gray: &image::GrayImage,
    ink: &[bool],
    bands: &[(Vec<usize>, TextBandScore)],
    radius: u32,
    primary_ink_luma_max: u8,
    artifact_luma_max: u8,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let mut cleaned = 0_u32;
    for (_, score) in bands {
        let [x0, y0, x1, y1] = score.bbox;
        let fill = local_background_fill(image, ink, score.bbox, radius.max(2), artifact_luma_max);
        let sx0 = x0.saturating_sub(radius);
        let sy0 = y0.saturating_sub(radius);
        let sx1 = x1.saturating_add(radius).min(width - 1);
        let sy1 = y1.saturating_add(radius).min(height - 1);
        for y in sy0..=sy1 {
            for x in sx0..=sx1 {
                let luma = gray.get_pixel(x, y).0[0];
                let index = y as usize * width as usize + x as usize;
                if luma > primary_ink_luma_max
                    && luma <= artifact_luma_max
                    && !ink.get(index).copied().unwrap_or(false)
                {
                    image.put_pixel(x, y, fill);
                    cleaned = cleaned.saturating_add(1);
                }
            }
        }
    }
    cleaned
}

#[cfg(not(target_arch = "wasm32"))]
fn clear_around(
    image: &mut image::RgbaImage,
    x: u32,
    y: u32,
    radius: u32,
    fill: image::Rgba<u8>,
) -> u32 {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return 0;
    }
    let x0 = x.saturating_sub(radius);
    let y0 = y.saturating_sub(radius);
    let x1 = (x + radius).min(width - 1);
    let y1 = (y + radius).min(height - 1);
    let mut count = 0_u32;
    for cy in y0..=y1 {
        for cx in x0..=x1 {
            image.put_pixel(cx, cy, fill);
            count = count.saturating_add(1);
        }
    }
    count
}

#[cfg(not(target_arch = "wasm32"))]
fn local_background_fill(
    image: &image::RgbaImage,
    ink: &[bool],
    bbox: [u32; 4],
    margin: u32,
    background_luma_min: u8,
) -> image::Rgba<u8> {
    let width = image.width();
    let height = image.height();
    if width == 0 || height == 0 {
        return image::Rgba([255, 255, 255, 0]);
    }

    let [x0, y0, x1, y1] = bbox;
    let sx0 = x0.saturating_sub(margin);
    let sy0 = y0.saturating_sub(margin);
    let sx1 = x1.saturating_add(margin).min(width - 1);
    let sy1 = y1.saturating_add(margin).min(height - 1);
    let mut sums = [0_u64; 4];
    let mut samples = 0_u64;

    for y in sy0..=sy1 {
        for x in sx0..=sx1 {
            let inside_component_bbox = x >= x0 && x <= x1 && y >= y0 && y <= y1;
            let index = y as usize * width as usize + x as usize;
            if inside_component_bbox || ink.get(index).copied().unwrap_or(false) {
                continue;
            }
            let pixel = image.get_pixel(x, y).0;
            let luma = (0.2126 * pixel[0] as f32
                + 0.7152 * pixel[1] as f32
                + 0.0722 * pixel[2] as f32) as u8;
            if pixel[3] > 0 && luma < background_luma_min {
                continue;
            }
            for channel in 0..4 {
                sums[channel] += pixel[channel] as u64;
            }
            samples += 1;
        }
    }

    if samples == 0 {
        return image::Rgba([255, 255, 255, 255]);
    }

    image::Rgba([
        (sums[0] / samples) as u8,
        (sums[1] / samples) as u8,
        (sums[2] / samples) as u8,
        (sums[3] / samples) as u8,
    ])
}

fn language_shaped_clear_bands(
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
) -> Vec<(Vec<usize>, TextBandScore)> {
    let raw_bands = language_shaped_bands(components, text_threshold);
    let scores: Vec<_> = raw_bands
        .into_iter()
        .filter_map(|band| {
            score_language_band_candidate(&band, components).map(|score| (band, score))
        })
        .collect();
    let strong: Vec<_> = scores
        .iter()
        .filter(|(_, score)| score.admitted)
        .map(|(_, score)| score.band.clone())
        .collect();
    scores
        .into_iter()
        .filter_map(|(band, score)| {
            if score.admitted || has_text_neighborhood_support(&score, &strong) {
                Some((band, score.band))
            } else {
                None
            }
        })
        .collect()
}

fn language_shaped_bands(
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    text_threshold: f32,
) -> Vec<Vec<usize>> {
    let mut glyphs: Vec<usize> = components
        .iter()
        .enumerate()
        .filter_map(|(index, (component, _))| {
            if is_glyph_sized(component, text_threshold) {
                Some(index)
            } else {
                None
            }
        })
        .collect();
    glyphs.sort_by_key(|&index| components[index].0.bbox[0]);
    let mut parent: Vec<usize> = (0..glyphs.len()).collect();
    for i in 0..glyphs.len() {
        for j in (i + 1)..glyphs.len() {
            if glyphs_are_line_neighbors(&components[glyphs[i]].0, &components[glyphs[j]].0) {
                union(&mut parent, i, j);
            }
        }
    }

    let mut bands: Vec<(usize, Vec<usize>)> = Vec::new();
    for (local_index, &component_index) in glyphs.iter().enumerate() {
        let root = find(&mut parent, local_index);
        if let Some((_, band)) = bands.iter_mut().find(|(band_root, _)| *band_root == root) {
            band.push(component_index);
        } else {
            bands.push((root, vec![component_index]));
        }
    }
    bands.into_iter().map(|(_, band)| band).collect()
}

fn glyphs_are_line_neighbors(a: &StrokeComponentTopology, b: &StrokeComponentTopology) -> bool {
    let [ax0, ay0, ax1, ay1] = a.bbox;
    let [bx0, by0, bx1, by1] = b.bbox;
    let aw = (ax1 - ax0 + 1).max(1) as f32;
    let bw = (bx1 - bx0 + 1).max(1) as f32;
    let ah = (ay1 - ay0 + 1).max(1) as f32;
    let bh = (by1 - by0 + 1).max(1) as f32;
    let acy = (ay0 + ay1) as f32 * 0.5;
    let bcy = (by0 + by1) as f32 * 0.5;
    let vertical_overlap = ay1 >= by0.saturating_sub(4) && by1 >= ay0.saturating_sub(4);
    let same_baseline = (acy - bcy).abs() <= ah.max(bh) * 1.25;
    let gap = if ax1 < bx0 {
        bx0 - ax1
    } else { ax0.saturating_sub(bx1) };
    let gap_limit = (aw.max(bw) * 5.0).max(18.0).min(64.0) as u32;
    gap <= gap_limit && (vertical_overlap || same_baseline)
}

fn find(parent: &mut [usize], index: usize) -> usize {
    if parent[index] != index {
        parent[index] = find(parent, parent[index]);
    }
    parent[index]
}

fn union(parent: &mut [usize], a: usize, b: usize) {
    let root_a = find(parent, a);
    let root_b = find(parent, b);
    if root_a != root_b {
        parent[root_b] = root_a;
    }
}

fn is_glyph_sized(component: &StrokeComponentTopology, text_threshold: f32) -> bool {
    let [x0, y0, x1, y1] = component.bbox;
    let width = x1 - x0 + 1;
    let height = y1 - y0 + 1;
    component.text_likeness >= (text_threshold - 0.1).max(0.4)
        && (2..=90).contains(&width)
        && (3..=70).contains(&height)
        && component.area <= 1_600
}

#[derive(Clone, Debug)]
struct TextBandScore {
    bbox: [u32; 4],
    band_width: u32,
    average_height: f32,
    compact_gap_ratio: f32,
    high_confidence: usize,
    pneuma_phoneme_prior: f32,
    language_shape_score: f32,
}

#[derive(Clone, Debug)]
struct TextBandCandidateScore {
    band: TextBandScore,
    admitted: bool,
}

fn score_language_band_candidate(
    band: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> Option<TextBandCandidateScore> {
    if band.len() < 4 {
        return None;
    }
    let mut sorted = band.to_vec();
    sorted.sort_by_key(|&index| components[index].0.bbox[0]);

    let mut min_x = u32::MAX;
    let mut min_y = u32::MAX;
    let mut max_x = 0_u32;
    let mut max_y = 0_u32;
    let mut total_height = 0_f32;
    let mut high_confidence = 0_usize;
    let mut max_gap = 0_u32;
    let mut compact_gaps = 0_usize;
    for (position, &index) in sorted.iter().enumerate() {
        let component = &components[index].0;
        let [x0, y0, x1, y1] = component.bbox;
        min_x = min_x.min(x0);
        min_y = min_y.min(y0);
        max_x = max_x.max(x1);
        max_y = max_y.max(y1);
        total_height += (y1 - y0 + 1) as f32;
        if component.text_likeness >= 0.7 {
            high_confidence += 1;
        }
        if position > 0 {
            let previous = &components[sorted[position - 1]].0;
            let previous_x1 = previous.bbox[2];
            let gap = x0.saturating_sub(previous_x1);
            max_gap = max_gap.max(gap);
            if gap <= 24 {
                compact_gaps += 1;
            }
        }
    }

    let band_width = max_x.saturating_sub(min_x).saturating_add(1);
    let average_height = total_height / sorted.len() as f32;
    let compact_gap_ratio = compact_gaps as f32 / sorted.len().saturating_sub(1).max(1) as f32;
    let spans_line = band_width >= (average_height * 4.0).max(32.0) as u32;
    let bounded_gap = max_gap <= (average_height * 5.0).max(28.0) as u32;
    let enough_rhythm = compact_gap_ratio >= 0.7;
    if !spans_line || !bounded_gap {
        return None;
    }
    let high_confidence_ratio = high_confidence as f32 / sorted.len() as f32;
    let length_score = (band_width as f32 / (average_height * 10.0).max(1.0)).min(1.0);
    let pneuma_phoneme_prior = score_visual_pneuma_phoneme_prior(&sorted, components);
    let language_shape_score = (0.32 * compact_gap_ratio
        + 0.30 * high_confidence_ratio
        + 0.20 * length_score
        + 0.18 * pneuma_phoneme_prior)
        .min(1.0);
    let band = TextBandScore {
        bbox: [min_x, min_y, max_x, max_y],
        band_width,
        average_height,
        compact_gap_ratio,
        high_confidence,
        pneuma_phoneme_prior,
        language_shape_score,
    };
    Some(TextBandCandidateScore {
        admitted: (enough_rhythm && high_confidence >= 2)
            || (compact_gap_ratio >= 0.55 && high_confidence >= 1 && pneuma_phoneme_prior >= 0.62),
        band,
    })
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum VisualPneumaClass {
    Vowel,
    Stop,
    Fricative,
    Nasal,
    Liquid,
    Punctuation,
    Unknown,
}

fn score_visual_pneuma_phoneme_prior(
    sorted_band: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> f32 {
    if sorted_band.len() < 2 {
        return 0.0;
    }
    let classes: Vec<_> = sorted_band
        .iter()
        .map(|&index| visual_pneuma_class(&components[index].0))
        .collect();
    let meaningful = classes
        .iter()
        .filter(|class| {
            !matches!(
                class,
                VisualPneumaClass::Unknown | VisualPneumaClass::Punctuation
            )
        })
        .count();
    if meaningful == 0 {
        return 0.0;
    }
    let vowels = classes
        .iter()
        .filter(|class| matches!(class, VisualPneumaClass::Vowel))
        .count();
    let consonants = classes
        .iter()
        .filter(|class| {
            matches!(
                class,
                VisualPneumaClass::Stop
                    | VisualPneumaClass::Fricative
                    | VisualPneumaClass::Nasal
                    | VisualPneumaClass::Liquid
            )
        })
        .count();
    let punctuation = classes
        .iter()
        .filter(|class| matches!(class, VisualPneumaClass::Punctuation))
        .count();
    let class_diversity = [
        VisualPneumaClass::Vowel,
        VisualPneumaClass::Stop,
        VisualPneumaClass::Fricative,
        VisualPneumaClass::Nasal,
        VisualPneumaClass::Liquid,
    ]
    .into_iter()
    .filter(|class| classes.iter().any(|candidate| candidate == class))
    .count() as f32
        / 5.0;
    let mut transitions = 0_u32;
    let mut plausible_transitions = 0_u32;
    for pair in classes.windows(2) {
        let a = pair[0];
        let b = pair[1];
        if matches!(a, VisualPneumaClass::Unknown) || matches!(b, VisualPneumaClass::Unknown) {
            continue;
        }
        transitions = transitions.saturating_add(1);
        if visual_pneuma_transition_is_plausible(a, b) {
            plausible_transitions = plausible_transitions.saturating_add(1);
        }
    }
    let transition_score = if transitions == 0 {
        0.35
    } else {
        plausible_transitions as f32 / transitions as f32
    };
    let vowel_balance = if vowels == 0 {
        0.35
    } else {
        (vowels as f32 / consonants.max(1) as f32).min(1.0)
    };
    let punctuation_score = if punctuation == 0 {
        0.65
    } else {
        (1.0 - punctuation as f32 / sorted_band.len() as f32).clamp(0.35, 0.9)
    };
    (0.38 * transition_score
        + 0.24 * class_diversity
        + 0.23 * vowel_balance
        + 0.15 * punctuation_score)
        .clamp(0.0, 1.0)
}

fn visual_pneuma_class(component: &StrokeComponentTopology) -> VisualPneumaClass {
    let [x0, y0, x1, y1] = component.bbox;
    let width = x1.saturating_sub(x0).saturating_add(1);
    let height = y1.saturating_sub(y0).saturating_add(1);
    if component.area <= 14 && width <= 8 && height <= 12 {
        return VisualPneumaClass::Punctuation;
    }
    if component.loops_estimate >= 1 && component.density >= 0.12 {
        return VisualPneumaClass::Vowel;
    }
    if component.endpoints <= 1 && component.aspect <= 1.2 && component.density >= 0.18 {
        return VisualPneumaClass::Nasal;
    }
    if component.junctions >= 2 || component.endpoints >= 3 {
        return VisualPneumaClass::Fricative;
    }
    if component.aspect >= 1.8 || component.aspect <= 0.55 {
        return VisualPneumaClass::Liquid;
    }
    if component.endpoints == 2 {
        return VisualPneumaClass::Stop;
    }
    VisualPneumaClass::Unknown
}

fn visual_pneuma_transition_is_plausible(a: VisualPneumaClass, b: VisualPneumaClass) -> bool {
    use VisualPneumaClass::{Fricative, Liquid, Nasal, Punctuation, Stop, Unknown, Vowel};
    match (a, b) {
        (Unknown, _) | (_, Unknown) => false,
        (Punctuation, _) => true,
        (_, Punctuation) => true,
        (Vowel, Vowel) => false,
        (Stop, Stop) => true,
        (Fricative, Fricative) => false,
        (Nasal, Nasal) => false,
        (Liquid, Liquid) => false,
        (Vowel, _) | (_, Vowel) => true,
        (Stop, Liquid) | (Stop, Fricative) | (Fricative, Liquid) | (Nasal, Stop) => true,
        (Liquid, Stop) | (Liquid, Fricative) | (Fricative, Stop) => true,
        _ => false,
    }
}

fn score_language_shaped_band(
    band: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> Option<TextBandScore> {
    let candidate = score_language_band_candidate(band, components)?;
    candidate.admitted.then_some(candidate.band)
}

fn has_text_neighborhood_support(
    candidate: &TextBandCandidateScore,
    strong: &[TextBandScore],
) -> bool {
    candidate.band.high_confidence >= 1
        && candidate.band.compact_gap_ratio >= 0.45
        && strong
            .iter()
            .any(|strong_band| bands_are_paragraph_neighbors(&candidate.band, strong_band))
}

fn is_residual_text_artifact(component: &StrokeComponentTopology, line: &TextBandScore) -> bool {
    let [x0, y0, x1, y1] = component.bbox;
    let width = x1 - x0 + 1;
    let height = y1 - y0 + 1;
    if width > 90 || height > 70 || component.area > 1_600 {
        return false;
    }
    let center_x = (x0 + x1) as f32 * 0.5;
    let center_y = (y0 + y1) as f32 * 0.5;
    let [lx0, ly0, lx1, ly1] = line.bbox;
    let margin_y = line.average_height.max(6.0);
    let inside_line_x = center_x >= lx0 as f32 && center_x <= lx1 as f32;
    let inside_line_y = center_y >= ly0 as f32 - margin_y && center_y <= ly1 as f32 + margin_y;
    inside_line_x && inside_line_y && component.text_likeness >= 0.35
}

fn residual_attachment_score(component: &StrokeComponentTopology, line: &TextBandScore) -> f32 {
    let base = line.language_shape_score * component.text_likeness;
    let pneuma_boost = 0.18 * line.pneuma_phoneme_prior;
    let punctuation_boost = if visual_pneuma_class(component) == VisualPneumaClass::Punctuation {
        0.24 * line.pneuma_phoneme_prior.max(line.language_shape_score)
    } else {
        0.0
    };
    (0.82 * base + pneuma_boost + punctuation_boost).clamp(0.0, 1.0)
}

fn is_kmeans_band_attached_residual(
    component: &StrokeComponentTopology,
    band: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
    line: &TextBandScore,
) -> bool {
    if band.len() < 4 || component.area > 1_600 || component.text_likeness < 0.32 {
        return false;
    }
    let Some(clusters) = kmeans_band_clusters(band, components) else {
        return false;
    };
    let center = component_center(component);
    clusters.iter().any(|cluster| {
        let x_margin = (line.average_height * 2.8).max(16.0);
        let y_margin = (line.average_height * 1.65).max(10.0);
        let close_to_cluster = center.0 >= cluster.min_x - x_margin
            && center.0 <= cluster.max_x + x_margin
            && (center.1 - cluster.center_y).abs() <= y_margin;
        let close_to_band = center.0 >= line.bbox[0] as f32 - x_margin
            && center.0 <= line.bbox[2] as f32 + x_margin
            && center.1 >= line.bbox[1] as f32 - y_margin
            && center.1 <= line.bbox[3] as f32 + y_margin;
        close_to_cluster && close_to_band
    })
}

#[derive(Clone, Copy, Debug)]
struct BandCluster {
    center_y: f32,
    min_x: f32,
    max_x: f32,
}

fn kmeans_band_clusters(
    band: &[usize],
    components: &[(StrokeComponentTopology, Vec<(usize, usize)>)],
) -> Option<[BandCluster; 2]> {
    if band.len() < 4 {
        return None;
    }
    let mut points: Vec<(f32, f32)> = band
        .iter()
        .filter_map(|&index| {
            components
                .get(index)
                .map(|(component, _)| component_center(component))
        })
        .collect();
    if points.len() < 4 {
        return None;
    }
    points.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
    let mut centers = [points[0].1, points[points.len() - 1].1];
    let mut assignments = vec![0_usize; points.len()];
    for _ in 0..8 {
        for (index, point) in points.iter().enumerate() {
            let d0 = (point.1 - centers[0]).abs();
            let d1 = (point.1 - centers[1]).abs();
            assignments[index] = if d0 <= d1 { 0 } else { 1 };
        }
        for cluster_index in 0..2 {
            let mut total = 0.0_f32;
            let mut count = 0_u32;
            for (assignment, point) in assignments.iter().zip(points.iter()) {
                if *assignment == cluster_index {
                    total += point.1;
                    count = count.saturating_add(1);
                }
            }
            if count > 0 {
                centers[cluster_index] = total / count as f32;
            }
        }
    }
    let mut clusters = [
        BandCluster {
            center_y: centers[0],
            min_x: f32::MAX,
            max_x: 0.0,
        },
        BandCluster {
            center_y: centers[1],
            min_x: f32::MAX,
            max_x: 0.0,
        },
    ];
    let mut counts = [0_u32, 0_u32];
    for (assignment, point) in assignments.iter().zip(points.iter()) {
        let cluster = &mut clusters[*assignment];
        cluster.min_x = cluster.min_x.min(point.0);
        cluster.max_x = cluster.max_x.max(point.0);
        counts[*assignment] = counts[*assignment].saturating_add(1);
    }
    if counts.contains(&0) {
        return None;
    }
    for cluster in &mut clusters {
        if cluster.min_x == f32::MAX {
            cluster.min_x = 0.0;
        }
    }
    Some(clusters)
}

fn component_center(component: &StrokeComponentTopology) -> (f32, f32) {
    let [x0, y0, x1, y1] = component.bbox;
    ((x0 + x1) as f32 * 0.5, (y0 + y1) as f32 * 0.5)
}

pub fn build_bridge_entries(example: &TextTopologyExample) -> Vec<TextTopologyBridgeEntry> {
    example
        .components
        .iter()
        .map(|component| {
            let [x0, y0, x1, y1] = component.bbox;
            let fw = example.width.max(1) as f32;
            let fh = example.height.max(1) as f32;
            let render_layer = if component.text_likeness >= 0.75 {
                "text"
            } else if component.text_likeness >= 0.55 {
                "unknown"
            } else {
                "art"
            };
            TextTopologyBridgeEntry {
                symbol: component_symbol(example, component),
                image_id: example.image_id.clone(),
                image_path: example.path.clone(),
                bbox: component.bbox,
                bbox_unit: [
                    round6(x0 as f32 / fw),
                    round6(y0 as f32 / fh),
                    round6(x1 as f32 / fw),
                    round6(y1 as f32 / fh),
                ],
                mesh_node: [
                    round6(((x0 + x1) as f32 * 0.5) / fw),
                    round6(((y0 + y1) as f32 * 0.5) / fh),
                    component.text_likeness,
                ],
                render_layer: render_layer.to_string(),
                topology: component.clone(),
            }
        })
        .collect()
}

pub fn build_text_line_candidates(
    example: &TextTopologyExample,
    text_threshold: f32,
) -> Vec<TextLineTopologyCandidate> {
    let components: Vec<_> = example
        .components
        .iter()
        .cloned()
        .map(|component| (component, Vec::new()))
        .collect();

    language_shaped_bands(&components, text_threshold)
        .into_iter()
        .enumerate()
        .filter_map(|(line_index, band)| {
            score_language_shaped_band(&band, &components).map(|score| {
                let fw = example.width.max(1) as f32;
                let fh = example.height.max(1) as f32;
                let bbox = score.bbox;
                TextLineTopologyCandidate {
                    symbol: format!("why:{}:line:{}", example.image_id, line_index),
                    image_id: example.image_id.clone(),
                    image_path: example.path.clone(),
                    bbox,
                    bbox_unit: [
                        round6(bbox[0] as f32 / fw),
                        round6(bbox[1] as f32 / fh),
                        round6(bbox[2] as f32 / fw),
                        round6(bbox[3] as f32 / fh),
                    ],
                    component_symbols: band
                        .iter()
                        .map(|&index| component_symbol(example, &components[index].0))
                        .collect(),
                    component_count: band.len() as u32,
                    band_width: score.band_width,
                    average_component_height: round4(score.average_height),
                    compact_gap_ratio: round4(score.compact_gap_ratio),
                    high_confidence_components: score.high_confidence as u32,
                    pneuma_phoneme_prior: round4(score.pneuma_phoneme_prior),
                    language_shape_score: round4(score.language_shape_score),
                }
            })
        })
        .collect()
}

pub fn build_residual_text_artifacts(
    example: &TextTopologyExample,
    text_threshold: f32,
) -> Vec<ResidualTextArtifact> {
    let components: Vec<_> = example
        .components
        .iter()
        .cloned()
        .map(|component| (component, Vec::new()))
        .collect();
    let admitted_bands = language_shaped_clear_bands(&components, text_threshold);
    let mut out = Vec::new();
    for (line_index, (band, score)) in admitted_bands.iter().enumerate() {
        let mut admitted = vec![false; components.len()];
        for &index in band {
            admitted[index] = true;
        }
        let line_symbol = format!("why:{}:line:{}", example.image_id, line_index);
        for (index, (component, _)) in components.iter().enumerate() {
            if admitted[index]
                || !is_residual_text_artifact(component, score)
                    && !is_kmeans_band_attached_residual(component, band, &components, score)
            {
                continue;
            }
            let fw = example.width.max(1) as f32;
            let fh = example.height.max(1) as f32;
            let component_symbol = component_symbol(example, component);
            let attachment_score = residual_attachment_score(component, score);
            out.push(ResidualTextArtifact {
                symbol: format!("{}:residual:{}", line_symbol, component.id),
                image_id: example.image_id.clone(),
                image_path: example.path.clone(),
                line_symbol: line_symbol.clone(),
                component_symbol,
                bbox: component.bbox,
                bbox_unit: [
                    round6(component.bbox[0] as f32 / fw),
                    round6(component.bbox[1] as f32 / fh),
                    round6(component.bbox[2] as f32 / fw),
                    round6(component.bbox[3] as f32 / fh),
                ],
                topology: component.clone(),
                artifact_kind: "primary_ink_inside_language_band".to_string(),
                cleanup_status: "semantic_review_required".to_string(),
                line_pneuma_phoneme_prior: round4(score.pneuma_phoneme_prior),
                attachment_score: round4(attachment_score),
                admission_score: round4(attachment_score),
            });
        }
    }
    out
}

pub fn build_residual_review_queue(residuals: &[ResidualTextArtifact]) -> Vec<ResidualReviewItem> {
    let mut groups: Vec<Vec<&ResidualTextArtifact>> = Vec::new();
    for residual in residuals {
        if let Some(group) = groups.iter_mut().find(|group| {
            group
                .first()
                .is_some_and(|item| item.line_symbol == residual.line_symbol)
        }) {
            group.push(residual);
        } else {
            groups.push(vec![residual]);
        }
    }

    let mut queue: Vec<_> = groups
        .into_iter()
        .filter_map(|group| {
            let first = *group.first()?;
            let mut min_x = u32::MAX;
            let mut min_y = u32::MAX;
            let mut max_x = 0_u32;
            let mut max_y = 0_u32;
            let mut total_score = 0.0_f32;
            let mut total_attachment_score = 0.0_f32;
            let mut max_score = 0.0_f32;
            let mut residual_symbols = Vec::new();
            for residual in &group {
                let [x0, y0, x1, y1] = residual.bbox;
                min_x = min_x.min(x0);
                min_y = min_y.min(y0);
                max_x = max_x.max(x1);
                max_y = max_y.max(y1);
                total_score += residual.admission_score;
                total_attachment_score += residual.attachment_score;
                max_score = max_score.max(residual.admission_score);
                residual_symbols.push(residual.symbol.clone());
            }
            let residual_count = group.len() as u32;
            let average_admission_score = total_score / residual_count.max(1) as f32;
            let average_attachment_score = total_attachment_score / residual_count.max(1) as f32;
            let count_pressure = (residual_count as f32 / 8.0).min(1.0);
            let review_priority = (0.45 * average_admission_score
                + 0.25 * max_score
                + 0.15 * average_attachment_score
                + 0.15 * count_pressure)
                .min(1.0);
            let recommendation = if review_priority >= 0.75 {
                "semantic_admit_or_protect_first".to_string()
            } else {
                "low_priority_review".to_string()
            };
            Some(ResidualReviewItem {
                symbol: format!("{}:review", first.line_symbol),
                image_id: first.image_id.clone(),
                image_path: first.image_path.clone(),
                line_symbol: first.line_symbol.clone(),
                bbox: [min_x, min_y, max_x, max_y],
                residual_symbols,
                residual_count,
                average_admission_score: round4(average_admission_score),
                max_admission_score: round4(max_score),
                average_attachment_score: round4(average_attachment_score),
                review_priority: round4(review_priority),
                recommendation,
            })
        })
        .collect();
    queue.sort_by(|a, b| {
        b.review_priority
            .partial_cmp(&a.review_priority)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| b.residual_count.cmp(&a.residual_count))
            .then_with(|| a.symbol.cmp(&b.symbol))
    });
    queue
}

pub fn build_mesh_text_admission_ledger(
    example: &TextTopologyExample,
    text_threshold: f32,
) -> Vec<MeshTextAdmissionRecord> {
    let components: Vec<_> = example
        .components
        .iter()
        .cloned()
        .map(|component| (component, Vec::new()))
        .collect();
    let admitted_bands = language_shaped_clear_bands(&components, text_threshold);
    let mut component_lines: Vec<Option<(usize, TextBandScore)>> = vec![None; components.len()];
    for (line_index, (band, score)) in admitted_bands.iter().enumerate() {
        for &index in band {
            component_lines[index] = Some((line_index, score.clone()));
        }
    }

    let fw = example.width.max(1) as f32;
    let fh = example.height.max(1) as f32;
    components
        .iter()
        .enumerate()
        .map(|(index, (component, _))| {
            let component_symbol = component_symbol(example, component);
            let line = component_lines[index].clone();
            let residual_line = admitted_bands
                .iter()
                .enumerate()
                .find(|(_, (band, score))| {
                    is_residual_text_artifact(component, score)
                        || is_kmeans_band_attached_residual(component, band, &components, score)
                });
            let (operation, mesh_admission_score, line_symbol) = if let Some((line_index, score)) =
                line
            {
                (
                    MeaningOperation {
                        subject: MeaningSubject::MeshObserver,
                        object: MeaningObject::TextBand,
                        verb: MeaningVerb::Fold,
                        frfvi_state: MeaningVerb::Fold,
                        knowledge_state: MeaningKnowledgeState::PositivePresence,
                        prior_state: MeaningObject::CandidateGlyph,
                        reason:
                            "component belongs to an admitted language-shaped mesh band"
                                .to_string(),
                    },
                    score.language_shape_score * component.text_likeness,
                    Some(format!("why:{}:line:{}", example.image_id, line_index)),
                )
            } else if let Some((line_index, (_, score))) = residual_line {
                (
                    MeaningOperation {
                        subject: MeaningSubject::LanguageObserver,
                        object: MeaningObject::ResidualArtifact,
                        verb: MeaningVerb::Interfere,
                        frfvi_state: MeaningVerb::Interfere,
                        knowledge_state: MeaningKnowledgeState::InActiveDemotion,
                        prior_state: MeaningObject::CandidateGlyph,
                        reason: "component sits near an admitted text band but failed primary admission; semantic review required".to_string(),
                    },
                    residual_attachment_score(component, score),
                    Some(format!("why:{}:line:{}", example.image_id, line_index)),
                )
            } else if component.text_likeness >= text_threshold {
                (
                    MeaningOperation {
                        subject: MeaningSubject::MeshObserver,
                        object: MeaningObject::DrawingMark,
                        verb: MeaningVerb::Vent,
                        frfvi_state: MeaningVerb::Vent,
                        knowledge_state: MeaningKnowledgeState::PositiveAbsence,
                        prior_state: MeaningObject::CandidateGlyph,
                        reason:
                            "component looked glyph-like locally but failed mesh line/paragraph admission"
                                .to_string(),
                    },
                    component.text_likeness,
                    None,
                )
            } else {
                (
                    MeaningOperation {
                        subject: MeaningSubject::TopologyObserver,
                        object: MeaningObject::InkComponent,
                        verb: MeaningVerb::Fork,
                        frfvi_state: MeaningVerb::Fork,
                        knowledge_state: MeaningKnowledgeState::NegativeUnknown,
                        prior_state: MeaningObject::InkComponent,
                        reason:
                            "component lacks enough local or mesh support for text admission"
                                .to_string(),
                    },
                    component.text_likeness,
                    None,
                )
            };
            MeshTextAdmissionRecord {
                symbol: format!("why:{}:admission:{}", example.image_id, component.id),
                image_id: example.image_id.clone(),
                image_path: example.path.clone(),
                component_symbol,
                bbox: component.bbox,
                bbox_unit: [
                    round6(component.bbox[0] as f32 / fw),
                    round6(component.bbox[1] as f32 / fh),
                    round6(component.bbox[2] as f32 / fw),
                    round6(component.bbox[3] as f32 / fh),
                ],
                operation,
                text_likeness: round4(component.text_likeness),
                mesh_admission_score: round4(mesh_admission_score),
                line_symbol,
            }
        })
        .collect()
}

pub fn build_rosetta_candidates(examples: &[TextTopologyExample]) -> Vec<RosettaCandidate> {
    let mut out = Vec::new();
    for example in examples {
        for component in &example.components {
            let (target, band, collision) = if component.text_likeness >= 0.75 {
                ("language_stroke_topology", "text_layer", 0)
            } else if component.text_likeness >= 0.55 {
                ("ambiguous_symbolic_stroke", "needs_anchor", 1)
            } else {
                ("non_language_ink_topology", "art_layer", 1)
            };
            out.push(RosettaCandidate {
                symbol: component_symbol(example, component),
                consensus_target: target.to_string(),
                consensus_confidence: component.text_likeness,
                utility_band: band.to_string(),
                predicted_meaning: target.to_string(),
                score: component.text_likeness,
                support: component.text_likeness,
                support_count: 1,
                avg_confidence: component.text_likeness,
                matched_ratio: 0.0,
                collision_size: collision,
            });
        }
    }
    out.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.symbol.cmp(&b.symbol))
    });
    out
}

fn component_symbol(example: &TextTopologyExample, component: &StrokeComponentTopology) -> String {
    format!("why:{}:stroke:{}", example.image_id, component.id)
}

fn connected_components(ink: &[bool], width: usize, height: usize) -> Vec<Vec<(usize, usize)>> {
    let mut seen = vec![false; ink.len()];
    let mut out = Vec::new();
    for y in 0..height {
        for x in 0..width {
            let i = y * width + x;
            if seen[i] || !ink[i] {
                continue;
            }
            seen[i] = true;
            let mut q = VecDeque::from([(x, y)]);
            let mut points = Vec::new();
            while let Some((cx, cy)) = q.pop_front() {
                points.push((cx, cy));
                for (nx, ny) in neighbors8(cx, cy, width, height) {
                    let ni = ny * width + nx;
                    if seen[ni] || !ink[ni] {
                        continue;
                    }
                    seen[ni] = true;
                    q.push_back((nx, ny));
                }
            }
            out.push(points);
        }
    }
    out
}

fn component_topology(
    id: u32,
    points: &[(usize, usize)],
    ink: &[bool],
    width: usize,
    height: usize,
    config: &TextTopologyConfig,
) -> StrokeComponentTopology {
    let (mut min_x, mut min_y) = (usize::MAX, usize::MAX);
    let (mut max_x, mut max_y) = (0_usize, 0_usize);
    for &(x, y) in points {
        min_x = min_x.min(x);
        max_x = max_x.max(x);
        min_y = min_y.min(y);
        max_y = max_y.max(y);
    }
    let bw = max_x - min_x + 1;
    let bh = max_y - min_y + 1;
    let area = points.len() as u32;
    let density = area as f32 / (bw * bh).max(1) as f32;
    let mut endpoints = 0_u32;
    let mut junctions = 0_u32;
    let mut edge_sum = 0_u32;
    if area <= config.max_component_area_for_text {
        for &(x, y) in points {
            let degree = neighbors8(x, y, width, height)
                .filter(|(nx, ny)| ink[ny * width + nx])
                .count() as u32;
            edge_sum = edge_sum.saturating_add(degree);
            if degree == 1 {
                endpoints = endpoints.saturating_add(1);
            } else if degree >= 3 {
                junctions = junctions.saturating_add(1);
            }
        }
    }
    let edges = edge_sum / 2;
    let loops_estimate = edges.saturating_sub(area).saturating_add(1);
    let aspect = bw as f32 / bh.max(1) as f32;
    let text_likeness = score_text_likeness(
        bw,
        bh,
        area,
        density,
        endpoints,
        junctions,
        loops_estimate,
        aspect,
    );
    StrokeComponentTopology {
        id,
        bbox: [min_x as u32, min_y as u32, max_x as u32, max_y as u32],
        area,
        density: round4(density),
        endpoints,
        junctions,
        loops_estimate,
        aspect: round4(aspect),
        text_likeness: round4(text_likeness),
    }
}

fn score_text_likeness(
    bw: usize,
    bh: usize,
    area: u32,
    density: f32,
    endpoints: u32,
    junctions: u32,
    loops: u32,
    aspect: f32,
) -> f32 {
    let mut score = 0.0_f32;
    if (3..=90).contains(&bw) {
        score += 0.18;
    }
    if (5..=70).contains(&bh) {
        score += 0.18;
    }
    if (5..=1600).contains(&area) {
        score += 0.14;
    }
    if (0.035..=0.75).contains(&density) {
        score += 0.14;
    }
    if endpoints >= 1 {
        score += 0.12;
    }
    if junctions <= 16 {
        score += 0.08;
    }
    if loops <= 8 {
        score += 0.08;
    }
    if (0.08..=5.5).contains(&aspect) {
        score += 0.08;
    }
    score.min(1.0)
}

fn neighbors8(
    x: usize,
    y: usize,
    width: usize,
    height: usize,
) -> impl Iterator<Item = (usize, usize)> {
    let x0 = x.saturating_sub(1);
    let y0 = y.saturating_sub(1);
    let x1 = (x + 1).min(width - 1);
    let y1 = (y + 1).min(height - 1);
    (y0..=y1).flat_map(move |ny| {
        (x0..=x1).filter_map(move |nx| {
            if nx == x && ny == y {
                None
            } else {
                Some((nx, ny))
            }
        })
    })
}

#[cfg(not(target_arch = "wasm32"))]
fn neighbors4(
    x: usize,
    y: usize,
    width: usize,
    height: usize,
) -> impl Iterator<Item = (usize, usize)> {
    let mut out = [(usize::MAX, usize::MAX); 4];
    let mut len = 0;
    if x > 0 {
        out[len] = (x - 1, y);
        len += 1;
    }
    if y > 0 {
        out[len] = (x, y - 1);
        len += 1;
    }
    if x + 1 < width {
        out[len] = (x + 1, y);
        len += 1;
    }
    if y + 1 < height {
        out[len] = (x, y + 1);
        len += 1;
    }
    out.into_iter().take(len)
}

fn round4(v: f32) -> f32 {
    (v * 10_000.0).round() / 10_000.0
}

fn round6(v: f32) -> f32 {
    (v * 1_000_000.0).round() / 1_000_000.0
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extracts_two_synthetic_stroke_components() {
        let width = 8_u32;
        let height = 6_u32;
        let mut luma = vec![255_u8; (width * height) as usize];
        for (x, y) in [(1, 1), (1, 2), (1, 3), (2, 3), (5, 1), (6, 1), (6, 2)] {
            luma[(y * width + x) as usize] = 0;
        }
        let example = analyze_luma_ink(
            "synthetic",
            "synthetic.png",
            &luma,
            width,
            height,
            &TextTopologyConfig::default(),
        )
        .unwrap();
        assert_eq!(example.ink_pixels, 7);
        assert_eq!(example.components.len(), 2);
        assert!(example.components.iter().all(|c| c.text_likeness > 0.0));
    }

    #[test]
    fn bridge_entries_preserve_page_coordinates() {
        let component = StrokeComponentTopology {
            id: 7,
            bbox: [10, 20, 30, 40],
            area: 12,
            density: 0.2,
            endpoints: 2,
            junctions: 0,
            loops_estimate: 0,
            aspect: 1.0,
            text_likeness: 0.8,
        };
        let example = TextTopologyExample {
            image_id: "panel".to_string(),
            path: "panel.png".to_string(),
            width: 100,
            height: 200,
            ink_pixels: 12,
            components: vec![component],
        };
        let bridge = build_bridge_entries(&example);
        assert_eq!(bridge[0].symbol, "why:panel:stroke:7");
        assert_eq!(bridge[0].render_layer, "text");
        assert_eq!(bridge[0].mesh_node, [0.2, 0.15, 0.8]);
    }
}
